def reverse_words_preserving_spaces(s: str) -> str:
    words = []
    length = len(s)
    i = 0
    while i < length:
        if s[i] != ' ':
            start = i
            while i < length and s[i] != ' ':
                i += 1
            words.append(s[start:i])
        else:
            i += 1
    words.reverse()
    result = []
    word_index = 0
    char_index = 0
    i = 0
    while i < length:
        if s[i] == ' ':
            result.append(' ')
            i += 1
        else:
            word = words[word_index]
            word_len = len(word)
            result.append(word[char_index])
            char_index += 1
            i += 1
            if char_index == word_len:
                word_index += 1
                char_index = 0
    return ''.join(result)

def are_anagrams(str1: str, str2: str) -> bool:
    from collections import Counter
    normalize = lambda s: Counter(c.lower() for c in s if not c.isspace())
    return normalize(str1) == normalize(str2)

def longest_palindromic_substring(s: str) -> str:
    if not s:
        return ""

    start, max_len = 0, 1

    def expand_around_center(left, right):
        while left >= 0 and right < len(s) and s[left] == s[right]:
            left -= 1
            right += 1
        return left + 1, right - 1

    for i in range(len(s)):
        l1, r1 = expand_around_center(i, i)
        l2, r2 = expand_around_center(i, i + 1)

        if r1 - l1 + 1 > max_len:
            start, max_len = l1, r1 - l1 + 1
        if r2 - l2 + 1 > max_len:
            start, max_len = l2, r2 - l2 + 1

    return s[start:start + max_len]

def run_length_encoding(s: str) -> str:
    if not s:
        return ""
    result = []
    count = 1
    prev_char = s[0]
    for char in s[1:]:
        if char == prev_char:
            count += 1
        else:
            result.append(str(count) + prev_char)
            prev_char = char
            count = 1
    result.append(str(count) + prev_char)
    return ''.join(result)

def decode_run_length(encoded_str: str) -> str:
    decoded = []
    count = 0
    for char in encoded_str:
        if char.isdigit():
            count = count * 10 + int(char)
        else:
            decoded.append(char * count)
            count = 0
    return ''.join(decoded)

def is_match(s: str, p: str) -> bool:
    m, n = len(s), len(p)
    dp = [[False] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = True

    for j in range(2, n + 1):
        if p[j - 1] == '*':
            dp[0][j] = dp[0][j - 2]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if p[j - 1] == '.' or p[j - 1] == s[i - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            elif p[j - 1] == '*':
                dp[i][j] = dp[i][j - 2]
                if p[j - 2] == '.' or p[j - 2] == s[i - 1]:
                    dp[i][j] = dp[i][j] or dp[i - 1][j]
            else:
                dp[i][j] = False
    return dp[m][n]

def string_permutations_unique(s: str) -> list[str]:
    from collections import Counter
    def backtrack(path, counter):
        if len(path) == len(s):
            result.append("".join(path))
            return
        for char in counter:
            if counter[char] > 0:
                path.append(char)
                counter[char] -= 1
                backtrack(path, counter)
                counter[char] += 1
                path.pop()
    result = []
    backtrack([], Counter(s))
    return result

