def roman_to_int(s: str) -> int:
    roman_map = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    total = 0
    prev_value = 0
    for char in reversed(s):
        value = roman_map[char]
        if value >= prev_value:
            total += value
        else:
            total -= value
        prev_value = value
    return total

def caesar_cipher(text: str, shift: int, encode: bool) -> str:
    if not encode:
        shift = -shift
    result = []
    for char in text:
        if char.isalpha():
            base = ord('A') if char.isupper() else ord('a')
            offset = (ord(char) - base + shift) % 26
            result.append(chr(base + offset))
        else:
            result.append(char)
    return ''.join(result)

def min_window_substring(s: str, t: str) -> str:
    from collections import Counter

    if not s or not t:
        return ""

    dict_t = Counter(t)
    required = len(dict_t)

    l, r = 0, 0
    formed = 0
    window_counts = {}
    ans = float("inf"), None, None

    while r < len(s):
        character = s[r]
        window_counts[character] = window_counts.get(character, 0) + 1

        if character in dict_t and window_counts[character] == dict_t[character]:
            formed += 1

        while l <= r and formed == required:
            character = s[l]

            if r - l + 1 < ans[0]:
                ans = (r - l + 1, l, r)

            window_counts[character] -= 1
            if character in dict_t and window_counts[character] < dict_t[character]:
                formed -= 1

            l += 1    
        r += 1

    if ans[0] == float("inf"):
        return ""
    else:
        return s[ans[1]:ans[2] + 1]

def group_anagrams(strs: list[str]) -> list[list[str]]:
    from collections import defaultdict
    groups = defaultdict(list)
    for s in strs:
        key = tuple(sorted(s))
        groups[key].append(s)
    return list(groups.values())

def is_balanced(s: str) -> bool:
    stack = []
    pairs = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in '([{':
            stack.append(char)
        elif char in ')]}':
            if not stack or stack.pop() != pairs[char]:
                return False
    return not stack

def longest_common_prefix(strs: list[str]) -> str:
    if not strs:
        return ""
    prefix = strs[0]
    for s in strs[1:]:
        while not s.startswith(prefix):
            prefix = prefix[:-1]
            if not prefix:
                return ""
    return prefix

def multiply(num1: str, num2: str) -> str:
    if num1 == "0" or num2 == "0":
        return "0"
    n1, n2 = len(num1), len(num2)
    result = [0] * (n1 + n2)
    for i in range(n1 - 1, -1, -1):
        for j in range(n2 - 1, -1, -1):
            mul = int(num1[i]) * int(num2[j])
            pos_low = i + j + 1
            pos_high = i + j
            sum_ = mul + result[pos_low]
            result[pos_low] = sum_ % 10
            result[pos_high] += sum_ // 10
    # Skip leading zeros
    start = 0
    while start < len(result) - 1 and result[start] == 0:
        start += 1
    return ''.join(map(str, result[start:]))

def count_distinct_subsequences(text: str, pattern: str) -> int:
    m, n = len(text), len(pattern)
    if n == 0:
        return 1
    if m == 0:
        return 0
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(m + 1):
        dp[i][0] = 1
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if text[i - 1] == pattern[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j]
            else:
                dp[i][j] = dp[i - 1][j]
    return dp[m][n]

def remove_all_adjacent_duplicates_repeatedly(s: str) -> str:
    stack = []
    for char in s:
        if stack and stack[-1] == char:
            while stack and stack[-1] == char:
                stack.pop()
        else:
            stack.append(char)
    result = ''.join(stack)
    if len(result) == len(s):
        return result
    else:
        return remove_all_adjacent_duplicates_repeatedly(result)

def is_rotation(s1: str, s2: str) -> bool:
    if len(s1) != len(s2):
        return False
    return s2 in s1 + s1

def first_non_repeating_character(s: str) -> str:
    from collections import Counter
    counts = Counter(s)
    for char in s:
        if counts[char] == 1:
            return char
    return ''

def is_match(s: str, p: str) -> bool:
    m, n = len(s), len(p)
    dp = [[False] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = True

    for j in range(1, n + 1):
        if p[j - 1] == '*':
            dp[0][j] = dp[0][j - 1]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if p[j - 1] == s[i - 1] or p[j - 1] == '?':
                dp[i][j] = dp[i - 1][j - 1]
            elif p[j - 1] == '*':
                dp[i][j] = dp[i][j - 1] or dp[i - 1][j]

    return dp[m][n]

def base64_encode(input_string: str) -> str:
    base64_chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
    bytes_data = input_string.encode('ascii')
    encoded = []

    # Process every 3 bytes
    for i in range(0, len(bytes_data), 3):
        triple = bytes_data[i:i+3]
        b = 0
        for byte in triple:
            b = (b << 8) + byte
        padding = 3 - len(triple)
        b <<= 8 * padding  # pad with zero bits if less than 3 bytes

        for j in range(18, -1, -6):
            if j == 18 and len(triple) < 1:
                encoded.append('=')
            elif j == 12 and len(triple) < 2:
                encoded.append('=')
            elif j == 6 and len(triple) < 3:
                encoded.append('=')
            else:
                index = (b >> j) & 0x3F
                encoded.append(base64_chars[index])

        if padding:
            encoded[-padding:] = '=' * padding

    return ''.join(encoded)

def decode_base64(encoded: str) -> str:
    base64_chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
    base64_map = {c: i for i, c in enumerate(base64_chars)}
    # Remove padding
    padding = encoded.count('=')
    encoded = encoded.rstrip('=')

    bits = 0
    bit_length = 0
    decoded_bytes = []

    for char in encoded:
        bits = (bits << 6) + base64_map[char]
        bit_length += 6
        while bit_length >= 8:
            bit_length -= 8
            byte = (bits >> bit_length) & 0xFF
            decoded_bytes.append(byte)
    if padding:
        decoded_bytes = decoded_bytes[:-padding]

    return bytes(decoded_bytes).decode('ascii')

def longest_substring_without_repeating_characters(s: str) -> int:
    char_index = {}
    start = 0
    max_length = 0
    for i, char in enumerate(s):
        if char in char_index and char_index[char] >= start:
            start = char_index[char] + 1
        char_index[char] = i
        max_length = max(max_length, i - start + 1)
    return max_length

def validate_ipv4_address(ip: str) -> bool:
    parts = ip.split('.')
    if len(parts) != 4:
        return False
    for part in parts:
        if not part.isdigit():
            return False
        if (part[0] == '0' and len(part) > 1):
            return False
        num = int(part)
        if num < 0 or num > 255:
            return False
    return True

def merge(nums1: list[int], m: int, nums2: list[int], n: int) -> None:
    i, j, k = m - 1, n - 1, m + n - 1
    while i >= 0 and j >= 0:
        if nums1[i] > nums2[j]:
            nums1[k] = nums1[i]
            i -= 1
        else:
            nums1[k] = nums2[j]
            j -= 1
        k -= 1
    while j >= 0:
        nums1[k] = nums2[j]
        j -= 1
        k -= 1

def find_kth_largest(nums: list[int], k: int) -> int:
    import heapq
    return heapq.nlargest(k, nums)[-1]

def find_all_pairs_with_target_sum(nums: list[int], target: int) -> list[tuple[int, int]]:
    seen = set()
    pairs = set()
    for num in nums:
        complement = target - num
        if complement in seen:
            pair = (min(num, complement), max(num, complement))
            pairs.add(pair)
        seen.add(num)
    return sorted(pairs)

def quicksort(arr: list[int]) -> list[int]:
    if len(arr) <= 1:
        return arr
    pivot = arr[len(arr) // 2]
    left = [x for x in arr if x < pivot]
    middle = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]
    return quicksort(left) + middle + quicksort(right)

def maximum_subarray_sum(nums: list[int]) -> int:
    if not nums:
        return 0
    max_current = max_global = nums[0]
    for num in nums[1:]:
        max_current = max(num, max_current + num)
        max_global = max(max_global, max_current)
    return max_global
